inline RSComplex c_add(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r + B.r;
	C.i = A.i + B.i;
	return C;
}

inline RSComplex c_sub(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r - B.r;
	C.i = A.i - B.i;
	return C;
}

inline RSComplex c_mul_full(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r * B.r - A.i * B.i;
	C.i = A.r * B.i + A.i * B.r;
	return C;
}

inline RSComplex c_div_full(RSComplex A, RSComplex B)
{
	RSComplex C;
	double denom = B.r * B.r + B.i * B.i;
	C.r = (A.r * B.r + A.i * B.i) / denom;
	C.i = (A.i * B.r - A.r * B.i) / denom;
	return C;
}

inline double c_abs_full(RSComplex A)
{
	return sqrt(A.r * A.r + A.i * A.i);
}

inline double fast_exp(double x)
{
	x = 1.0 + x * 0.000244140625;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	return x;
}

inline RSComplex fast_cexp(RSComplex z)
{
	double x = z.r;
	double y = z.i;
	double t1 = fast_exp(x);
	RSComplex t4;
	t4.r = cos(y);
	t4.i = sin(y);
	RSComplex t5;
	t5.r = t1;
	t5.i = 0.0;
	return c_mul_full(t5, t4);
}

inline RSComplex fast_nuclear_W(RSComplex Z)
{
	if(c_abs_full(Z) < 6.0)
	{
		RSComplex prefactor = {0.0, 8.124330e+01};
		RSComplex t1 = {0.0, 12.0};
		RSComplex t2 = {12.0, 0.0};
		RSComplex imag1 = {0.0, 1.0};
		RSComplex one = {1.0, 0.0};

		RSComplex W = c_div_full(
			c_mul_full(imag1, c_sub(one, fast_cexp(c_mul_full(t1, Z)))),
			c_mul_full(t2, Z)
		);

		RSComplex sum = {0.0, 0.0};
		for(int n = 0; n < 10; n++)
		{
			RSComplex t3 = {fnw_neg_1n[n], 0.0};
			RSComplex top = c_sub(c_mul_full(t3, fast_cexp(c_mul_full(t1, Z))), one);
			RSComplex t4 = {fnw_denominator_left[n], 0.0};
			RSComplex t5 = {144.0, 0.0};
			RSComplex bot = c_sub(t4, c_mul_full(t5, c_mul_full(Z, Z)));
			RSComplex t6 = {fnw_an[n], 0.0};
			sum = c_add(sum, c_mul_full(t6, c_div_full(top, bot)));
		}
		W = c_add(W, c_mul_full(prefactor, c_mul_full(Z, sum)));
		return W;
	}
	else
	{
		RSComplex a = {0.512424224754768462984202823134979415014943561548661637413182, 0.0};
		RSComplex b = {0.275255128608410950901357962647054304017026259671664935783653, 0.0};
		RSComplex c = {0.051765358792987823963876628425793170829107067780337219430904, 0.0};
		RSComplex d = {2.724744871391589049098642037352945695982973740328335064216346, 0.0};
		RSComplex imag1 = {0.0, 1.0};
		RSComplex Z2 = c_mul_full(Z, Z);

		RSComplex W = c_mul_full(
			c_mul_full(Z, imag1),
			c_add(c_div_full(a, c_sub(Z2, b)), c_div_full(c, c_sub(Z2, d)))
		);

		return W;
	}
}

inline double LCG_random_double(ulong *seed)
{
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	const ulong mask = 0x7FFFFFFFFFFFFFFFUL;
	*seed = (a * (*seed) + c) & mask;
	return (double)(*seed) / 9223372036854775808.0;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong a_init = 2806196910506780709UL;
	const ulong c_init = 1UL;
	const ulong mask = 0x7FFFFFFFFFFFFFFFUL;

	ulong a = a_init;
	ulong c = c_init;
	ulong a_new = 1UL;
	ulong c_new = 0UL;

	n &= mask;

	while(n > 0UL)
	{
		if(n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1UL;
	}

	return (a_new * seed + c_new) & mask;
}

inline int pick_mat(ulong *seed)
{
	double dist[12];
	dist[0]  = 0.140;
	dist[1]  = 0.052;
	dist[2]  = 0.275;
	dist[3]  = 0.134;
	dist[4]  = 0.154;
	dist[5]  = 0.064;
	dist[6]  = 0.066;
	dist[7]  = 0.055;
	dist[8]  = 0.008;
	dist[9]  = 0.015;
	dist[10] = 0.025;
	dist[11] = 0.013;

	double roll = LCG_random_double(seed);

	for(int i = 0; i < 12; i++)
	{
		double running = 0.0;
		for(int j = i; j > 0; j--)
			running = running + dist[j];
		if(roll < running)
			return i;
	}

	return 0;
}

inline void calculate_sig_T(
	int nuc,
	double E,
	Input input,
	__global const double *pseudo_K0RS,
	RSComplex *sigTfactors)
{
	for(int i = 0; i < 4; i++)
	{
		double phi = pseudo_K0RS[nuc * input.numL + i] * sqrt(E);

		if(i == 1)
			phi -= -atan(phi);
		else if(i == 2)
			phi -= atan(3.0 * phi / (3.0 - phi * phi));
		else if(i == 3)
			phi -= atan(phi * (15.0 - phi * phi) / (15.0 - 6.0 * phi * phi));

		phi *= 2.0;
		sigTfactors[i].r = cos(phi);
		sigTfactors[i].i = -sin(phi);
	}
}

inline void calculate_micro_xs(
	double *micro_xs,
	int nuc,
	double E,
	Input input,
	__global const int *n_windows,
	__global const double *pseudo_K0RS,
	__global const Window *windows,
	__global const Pole *poles,
	int max_num_windows,
	int max_num_poles)
{
	double sigT;
	double sigA;
	double sigF;
	double sigE;

	double spacing = 1.0 / (double)n_windows[nuc];
	int window = (int)(E / spacing);
	if(n_windows[nuc] == window)
		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	for(int i = w.start; i < w.end; i++)
	{
		Pole pole = poles[nuc * max_num_poles + i];
		RSComplex t1 = {0.0, 1.0};
		RSComplex t2 = {sqrt(E), 0.0};
		RSComplex PSIIKI = c_div_full(t1, c_sub(pole.MP_EA, t2));
		RSComplex E_c = {E, 0.0};
		RSComplex CDUM = c_div_full(PSIIKI, E_c);

		sigT += c_mul_full(pole.MP_RT, c_mul_full(CDUM, sigTfactors[(int)pole.l_value])).r;
		sigA += c_mul_full(pole.MP_RA, CDUM).r;
		sigF += c_mul_full(pole.MP_RF, CDUM).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

inline void calculate_micro_xs_doppler(
	double *micro_xs,
	int nuc,
	double E,
	Input input,
	__global const int *n_windows,
	__global const double *pseudo_K0RS,
	__global const Window *windows,
	__global const Pole *poles,
	int max_num_windows,
	int max_num_poles)
{
	double sigT;
	double sigA;
	double sigF;
	double sigE;

	double spacing = 1.0 / (double)n_windows[nuc];
	int window = (int)(E / spacing);
	if(n_windows[nuc] == window)
		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	double dopp = 0.5;

	for(int i = w.start; w.end > i; i++)
	{
		Pole pole = poles[nuc * max_num_poles + i];

		RSComplex E_c = {E, 0.0};
		RSComplex dopp_c = {dopp, 0.0};
		RSComplex Z = c_mul_full(c_sub(E_c, pole.MP_EA), dopp_c);
		RSComplex faddeeva = fast_nuclear_W(Z);

		sigT += c_mul_full(pole.MP_RT, c_mul_full(faddeeva, sigTfactors[(int)pole.l_value])).r;
		sigA += c_mul_full(pole.MP_RA, faddeeva).r;
		sigF += c_mul_full(pole.MP_RF, faddeeva).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

inline void calculate_macro_xs(
	double *macro_xs,
	int mat,
	double E,
	Input input,
	__global const int *num_nucs,
	__global const int *mats,
	int max_num_nucs,
	__global const double *concs,
	__global const int *n_windows,
	__global const double *pseudo_K0RS,
	__global const Window *windows,
	__global const Pole *poles,
	int max_num_windows,
	int max_num_poles)
{
	for(int i = 0; i < 4; i++)
		macro_xs[i] = 0.0;

	for(int i = 0; i < num_nucs[mat]; i++)
	{
		double micro_xs[4];
		int nuc = mats[mat * max_num_nucs + i];

		if(input.doppler == 1)
			calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
		else
			calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

		for(int j = 0; j < 4; j++)
			macro_xs[j] += micro_xs[j] * concs[mat * max_num_nucs + i];
	}
}

__kernel void macro_xs_lookup_kernel(
	Input input,
	__global const int *num_nucs,
	__global const int *mats,
	int max_num_nucs,
	__global const double *concs,
	__global const int *n_windows,
	__global const double *pseudo_K0RS,
	__global const Window *windows,
	__global const Pole *poles,
	int max_num_windows,
	int max_num_poles,
	__global int *verification_array)
{
	ulong idx = (ulong)get_global_id(0);
	if(idx >= (ulong)input.lookups)
		return;

	ulong seed = (ulong)STARTING_SEED;
	seed = fast_forward_LCG(seed, 2UL * idx);

	double E = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	double macro_xs[4];
	calculate_macro_xs(
		macro_xs, mat, E, input,
		num_nucs, mats, max_num_nucs, concs,
		n_windows, pseudo_K0RS, windows, poles,
		max_num_windows, max_num_poles
	);

	double max_val = -1.7976931348623157e+308;
	int max_idx = 0;
	for(int x = 0; x < 4; x++)
	{
		if(max_val < macro_xs[x])
		{
			max_val = macro_xs[x];
			max_idx = x;
		}
	}

	verification_array[idx] = max_idx + 1;
}
